var minTimeToType = function(word) {
    let total = word.length;
    let prev = 0;
    for (const ch of word) {
        const c = ch.charCodeAt(0) - 97;
        const d = Math.abs(c - prev);
        total += Math.min(d, 26 - d);
        prev = c;
    }
    return total;
};
